  const transStart2 = newContent.indexOf("const TRANSLATIONS: Record<Language, Translation> = {");
  const blockStart = newContent.indexOf(`  ${lang}: {`, transStart2);
  const blockEnd = nextLang ? newContent.indexOf(`  ${nextLang}: {`, transStart2) : newContent.indexOf("};\n\n// --- Helper Functions ---");
  if (blockStart === -1 || blockEnd === -1) continue;
