  const impScreen = `{ title: "${trans.imp_title}", description: ${JSON.stringify(trans.imp_desc)}, prompt: "A medical infographic showing important instructions." },
      `;
  block = block.substring(0, lastScreenStart) + impScreen + block.substring(lastScreenStart);
